#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, K;
    cin >> N;
    vector<int> a(N);
    for (int i = 0; i < N; ++i) cin >> a[i];
    cin >> K;

    if (N == 0) return 0;

    // Normalize: positive K = right shift, negative K = left shift
    // Right shift by K is equivalent to left shift by N - (K mod N)
    // We'll handle negatives by converting to an equivalent positive rotation
    K %= N;
    if (K < 0) K += N;  // now K in [0, N-1], representing a right shift

    // If K == 0, array is unchanged
    // Right shift by K means: last K elements move to front
    // Equivalently: rotate left by N-K
    if (K > 0) {
        // Rotate left by N-K -> bring last K elements to front
        rotate(a.begin(), a.begin() + (N - K), a.end());
    }

    for (int i = 0; i < N; ++i) {
        if (i > 0) cout << ' ';
        cout << a[i];
    }
    cout << '\n';

    return 0;
}
